    if file_name.count('.') != 1:
        return 'No'

    # Split the file name into base and extension
    base, extension = file_name.split('.')

    # Check that base is not empty and starts with a Latin letter
    if not base or not base[0].isalpha():
        return 'No'

    # Check that extension is one of the allowed options
    if extension not in ('txt', 'exe', 'dll'):
        return 'No'

    # Count numeric characters in the entire string
    digit_count = sum(1 for char in file_name if char.isdigit())
    if digit_count > 3:
        return 'No'

